INSERT INTO `attractions` (`id`, `name`, `description`, `location`, `latitude`, `longitude`, `category`, `image_url`, `created_at`) VALUES
(36, 'Machu Picchu', 'Santuario histórico e imponente ciudadela incaica ubicada en la cresta de una montaña. Obra maestra de la arquitectura y la ingeniería precolombina, rodeada de templos, terrazas agrícolas y canales de agua. Ideal para turismo cultural, místico y de aventura.', 'Cusco, Urubamba', -13.163141, -72.544963, 'Arqueológico', 'https://images.unsplash.com/photo-1587595431973-160d0d94add1', '2026-07-04 01:26:23'),
(37, 'Sacsayhuamán', 'Fortaleza ceremonial inca famosa por sus enormes muros de roca caliza tallada que encajan con precisión milimétrica. Lugar sagrado donde se celebra el Inti Raymi o Fiesta del Sol, ofreciendo una vista panorámica de la ciudad del Cusco.', 'Cusco, Cusco', -13.507881, -71.981745, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac', '2026-07-04 01:26:23'),
(38, 'Ollantaytambo', 'Pueblo inca viviente y sitio arqueológico que funcionó como un centro militar, religioso y agrícola. Destaca por sus calles empedradas originales, canales de agua activos y un imponente templo dedicado al Sol en la cima de la montaña.', 'Cusco, Urubamba', -13.258414, -72.263442, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1', '2026-07-04 01:26:23'),
(39, 'Moray', 'Laboratorio agrícola inca conformado por un sistema de terrazas concéntricas dispuestas en anfiteatros gigantes. Cada nivel recrea un microclima diferente, permitiendo la domesticación y experimentación de una gran variedad de cultivos andinos.', 'Cusco, Maras', -13.329864, -72.197022, 'Arqueológico', 'https://images.unsplash.com/photo-1569336415962-a4bd9f69cd83', '2026-07-04 01:26:23'),
(40, 'Salineras de Maras', 'Complejo de más de 3,000 pozas de sal de origen pre-inca que se llenan con agua subterránea hipersalina. Al evaporarse el agua por el sol, se extrae la famosa sal rosada de Maras de forma artesanal. Un paisaje blanco único.', 'Cusco, Maras', -13.303362, -72.154133, 'Naturaleza', 'https://images.unsplash.com/photo-1610123598147-f632aa18b275', '2026-07-04 01:26:23'),
(41, 'Choquequirao', 'Conocida como la hermana sagrada de Machu Picchu, es una impresionante ciudadela incaica oculta entre las montañas del Salkantay. De difícil acceso pedestre, ideal para el trekking extremo y la observación de cóndores y andenerías.', 'Cusco, La Convención', -13.389766, -72.873211, 'Aventura', 'https://images.unsplash.com/photo-1544735716-392fe2489ffa', '2026-07-04 01:26:23'),
(42, 'Vinicunca (Montaña de 7 Colores)', 'Famosa montaña teñida de franjas de colores debido a una compleja combinación de minerales. Ubicada a más de 5,000 metros sobre el nivel del mar, ofrece un paisaje altoandino surrealista y desafiante para los amantes del trekking.', 'Cusco, Quispicanchi', -13.869614, -71.303038, 'Naturaleza', 'https://images.unsplash.com/photo-1596120236168-18be57f722a4', '2026-07-04 01:26:23'),
(43, 'Lago Titicaca', 'El lago navegable más alto del mundo, cuna de leyendas andinas y mitos de origen inca. Sus aguas azules albergan biodiversidad única y conectan a comunidades que preservan tradiciones ancestrales en sus islas.', 'Puno, Puno', -15.75, -69.416667, 'Naturaleza', 'https://images.unsplash.com/photo-1528164344705-47542687000d', '2026-07-04 01:26:23'),
(44, 'Islas Flotantes de los Uros', 'Comunidad ancestral que vive sobre islas artificiales construidas enteramente de totora sobre el Lago Titicaca. Mantienen sus costumbres de pesca, artesanía y navegación en balsas tradicionales de totora.', 'Puno, Puno', -15.814324, -69.973412, 'Cultural', 'https://images.unsplash.com/photo-1590004953392-5aba2e72269a', '2026-07-04 01:26:23'),
(45, 'Isla de Taquile', 'Isla en el Lago Titicaca cuyos pobladores conservan intactas sus costumbres coloniales y pre-incas. Destaca por su arte textil, reconocido por la UNESCO, donde los varones tejen desde niños prendas de altísima calidad.', 'Puno, Puno', -15.771963, -69.686523, 'Cultural', 'https://images.unsplash.com/photo-1568231266584-8b54906cd523', '2026-07-04 01:26:23'),
(46, 'Plaza de Armas de Arequipa', 'Núcleo histórico de la Ciudad Blanca, rodeada por imponentes portales construidos en sillar (piedra volcánica blanca) y coronada por la majestuosa Catedral Basílica. Ofrece vistas impresionantes al volcán Misti.', 'Arequipa, Arequipa', -16.398863, -71.536961, 'Cultural', 'https://images.unsplash.com/photo-1583794713782-b36d1a5563a6', '2026-07-04 01:26:23'),
(47, 'Monasterio de Santa Catalina', 'Una ciudadela religiosa dentro de la ciudad de Arequipa. Este convento de clausura destaca por sus calles de intensos colores azul y terracota, patios con claustros, fuentes y una rica pinacoteca colonial.', 'Arequipa, Arequipa', -16.395254, -71.536944, 'Histórico', 'https://images.unsplash.com/photo-1599925232924-406cb75267ea', '2026-07-04 01:26:23'),
(48, 'Cañón del Colca', 'Uno de los cañones más profundos del mundo, rodeado de paisajes altoandinos, andenerías agrícolas pre-incas y pueblos tradicionales. Es el lugar por excelencia para el avistamiento del majestuoso vuelo del cóndor andino.', 'Arequipa, Caylloma', -15.609214, -71.901511, 'Naturaleza', 'https://images.unsplash.com/photo-1541849546-216549ae216d', '2026-07-04 01:26:23'),
(49, 'Oasis de Huacachina', 'Una laguna natural rodeada de palmeras y enormes dunas de arena en medio del desierto costero de Ica. Destino turístico ideal para la práctica de deportes de aventura como el sandboard y paseos en carros tubulares.', 'Ica, Ica', -14.087462, -75.763321, 'Aventura', 'https://images.unsplash.com/photo-1534447677768-be436bb09401', '2026-07-04 01:26:23'),
(50, 'Líneas de Nazca', 'Enigmáticos geoglifos precolombinos trazados sobre las pampas de Nazca que representan figuras antropomorfas, zoomorfas y geométricas gigantes. Solo pueden ser apreciadas en su total magnitud mediante un sobrevuelo aéreo.', 'Ica, Nazca', -14.739027, -75.130005, 'Arqueológico', 'https://images.unsplash.com/photo-1622325492193-273a5a76c024', '2026-07-04 01:26:23'),
(51, 'Reserva Nacional de Paracas', 'Área protegida costera donde el desierto se encuentra con el océano Pacífico. Alberga espectaculares formaciones rocosas, playas de arena roja y una impresionante biodiversidad marina que incluye lobos marinos y aves guaneras.', 'Ica, Pisco', -13.864388, -76.286241, 'Naturaleza', 'https://images.unsplash.com/photo-1594225026405-b1a7df75d1d6', '2026-07-04 01:26:23'),
(52, 'Islas Ballestas', 'Grupo de islas rocosas cerca de Paracas que albergan una inmensa colonia de lobos marinos, pingüinos de Humboldt y millones de aves guaneras. Los recorridos en lancha permiten apreciar de cerca esta fauna y el famoso geoglifo del Candelabro.', 'Ica, Pisco', -13.731792, -76.398642, 'Naturaleza', 'https://images.unsplash.com/photo-1589558416041-0ca5062eb538', '2026-07-04 01:26:23'),
(53, 'Centro Histórico de Lima', 'Patrimonio de la Humanidad que alberga templos, conventos y casonas coloniales con sus característicos balcones de madera tallada. Incluye la Plaza Mayor, el Palacio de Gobierno y las catacumbas del Convento de San Francisco.', 'Lima, Lima', -12.046374, -77.029578, 'Histórico', 'https://images.unsplash.com/photo-1580618672591-eb180b1a973f', '2026-07-04 01:26:23'),
(54, 'Malecón de Miraflores', 'Extenso parque lineal ubicado al borde de un acantilado con vista directa al océano Pacífico. Espacio urbano perfecto para paseos a pie, ciclismo, parapente y visitas al Parque del Amor con sus mosaicos coloridos.', 'Lima, Miraflores', -12.125812, -77.036603, 'Urbano', 'https://images.unsplash.com/photo-1531968455001-5c5277a9b133', '2026-07-04 01:26:23'),
(55, 'Huaca Pucllana', 'Gran centro ceremonial y administrativo de adobe y patrimonio de la cultura Lima (siglos V-VIII d.C.). Esta imponente pirámide trunca contrasta fuertemente al estar situada en medio de los modernos edificios residenciales de Miraflores.', 'Lima, Miraflores', -12.111166, -77.033668, 'Arqueológico', 'https://images.unsplash.com/photo-1619542402915-dcaf30e4e2a1', '2026-07-04 01:26:23'),
(56, 'Ciudadela de Chan Chan', 'La ciudad de barro más grande de la América prehispánica, antigua capital del reino Chimú. Compuesta por ciudadelas amuralladas, templos, plazas y depósitos decorados con relieves geométricos y marinos.', 'La Libertad, Trujillo', -8.108422, -79.070961, 'Arqueológico', 'https://images.unsplash.com/photo-1634591461947-f58c704f0f0c', '2026-07-04 01:26:23'),
(57, 'Huacas del Sol y de la Luna', 'Santuarios preíncas de la cultura Moche. La Huaca de la Luna destaca por sus impresionantes murales polícromos en relieve que representan a su deidad principal, el dios degollador Ai Apaec.', 'La Libertad, Trujillo', -8.135311, -78.991583, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1', '2026-07-04 01:26:23'),
(58, 'Complejo Arqueológico El Brujo', 'Centro ceremonial Moche donde se descubrió la tumba de la Dama de Cao, gobernante mujer con tatuajes visibles. El sitio cuenta con relieves polícromos y un museo de sitio de vanguardia frente al mar.', 'La Libertad, Ascope', -7.915722, -79.303914, 'Arqueológico', 'https://images.unsplash.com/photo-1544735716-392fe2489ffa', '2026-07-04 01:26:23'),
(59, 'Museo Tumbas Reales de Sipán', 'Espectacular museo con arquitectura inspirada en las pirámides moche, que custodia el ajuar funerario de oro, plata y gemas del Señor de Sipán, uno de los descubrimientos arqueológicos más importantes de América.', 'Lambayeque, Lambayeque', -6.702711, -79.905624, 'Cultural', 'https://images.unsplash.com/photo-1568231266584-8b54906cd523', '2026-07-04 01:26:23'),
(60, 'Kuelap', 'Fortaleza amurallada de la cultura Chachapoyas ubicada en una cresta montañosa. Sus gigantescas murallas de piedra resguardan cientos de viviendas circulares decoradas con frisos de rombos, accesible vía teleférico.', 'Amazonas, Luya', -6.417778, -77.923611, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac', '2026-07-04 01:26:23'),
(61, 'Parque Nacional del Manu', 'Uno de los mayores santuarios de biodiversidad del planeta. Abarca desde los Andes orientales hasta la llanura amazónica baja, albergando miles de especies de aves, mamíferos como el jaguar y el maquisapa, y comunidades nativas no contactadas.', 'Madre de Dios, Manu', -12.261234, -71.748392, 'Naturaleza', 'https://images.unsplash.com/photo-1516026672322-bc52d61a55d5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(62, 'Reserva Nacional Tambopata', 'Destino amazónico megadiverso famoso por sus colpas de guacamayos, donde cientos de aves de colores se reúnen a comer arcilla. Alberga el Lago Sandoval, un espejo de agua rodeado de palmeras habitado por nutrias gigantes de río.', 'Madre de Dios, Tambopata', -12.793847, -69.294128, 'Naturaleza', 'https://images.unsplash.com/photo-1547036967-23d11aacaee0?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(63, 'Reserva Nacional Pacaya Samiria', 'Conocida como la selva de los espejos por el reflejo perfecto del cielo en sus aguas oscuras. Es el área protegida inundable más grande del Perú, hábitat del delfín rosado del Amazonas, el paiche, caimanes y monos.', 'Loreto, Loreto', -4.833333, -74.333333, 'Naturaleza', 'https://images.unsplash.com/photo-1581404175344-bd43e38101a0?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(64, 'Catarata de Gocta', 'Una de las cascadas más altas del mundo, con una impresionante caída libre de agua en dos saltos que suma 771 metros. Se encuentra escondida en un frondoso bosque de neblina habitado por el gallito de las rocas.', 'Amazonas, Bongará', -5.931944, -77.8825, 'Aventura', 'https://images.unsplash.com/photo-1433832597046-4f10e10ac764?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(65, 'Laguna de los Cóndores', 'Espectacular laguna mística rodeada de selva alta donde en 1996 se descubrieron más de 200 momias incas y chachapoyas guardadas en mausoleos intactos en los acantilados. Ideal para trekking de aventura extrema.', 'Amazonas, Chachapoyas', -6.850556, -77.698889, 'Arqueológico', 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(66, 'Catarata del Tirol', 'Hermosa caída de agua de más de 30 metros de altura rodeada de una exuberante vegetación tropical en la selva central. El camino de herradura para llegar permite observar mariposas exóticas, orquídeas y flora nativa.', 'Junín, Chanchamayo', -11.026412, -75.319472, 'Naturaleza', 'https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(67, 'Parque Nacional Tingo María', 'Hogar de la cadena montañosa conocida como La Bella Durmiente por su silueta de mujer recostada. Alberga la Cueva de las Lechuzas, una enorme gruta de piedra caliza habitada por guácharos y murciélagos.', 'Huánuco, Leoncio Prado', -9.313889, -76.019444, 'Naturaleza', 'https://images.unsplash.com/photo-1544816155-12df9643f363?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(68, 'Laguna Llanganuco (Chinancocha)', 'Espejo de agua de un color verde turquesa intenso ubicado en el Parque Nacional Huascarán. Reposa en un estrecho valle glacial flanqueado por los majestuosos nevados Huascarán, Huandoy y Yanapaccha.', 'Ancash, Yungay', -9.066421, -77.652134, 'Naturaleza', 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(69, 'Laguna 69', 'Famosa laguna de aguas color azul turquesa brillante situada a 4,600 metros sobre el nivel del mar. Es uno de los destinos de senderismo de un día más populares del mundo por sus vistas directas al nevado Chacraraju.', 'Ancash, Yungay', -9.012543, -77.611145, 'Aventura', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(70, 'Chavín de Huántar', 'Centro ceremonial preínca monumental de la cultura Chavín. Destaca por su compleja red de galerías subterráneas de piedra, el Lanzón Monolítico, las Cabezas Clavas y su avanzado sistema de acústica ritual.', 'Ancash, Huari', -9.593889, -77.1775, 'Arqueológico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(71, 'Pastoruri', 'Nevado de fácil acceso que forma parte de la ruta del cambio climático. Permite observar los efectos del retroceso glacial, además de hermosas lagunas congeladas y las colosales plantas de Puya Raimondi en el camino.', 'Ancash, Bolognesi', -9.880278, -77.197778, 'Naturaleza', 'https://images.unsplash.com/photo-1483728642387-6c3bdd6c93e5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(72, 'Cañón del Pato', 'Impresionante formación rocosa creada por el río Santa donde las cordilleras Blanca y Negra se aproximan a solo metros de distancia. Su carretera cuenta con decenas de túneles rústicos picados en la roca.', 'Ancash, Huaylas', -8.847778, -77.854444, 'Aventura', 'https://images.unsplash.com/photo-1518098268026-4e43a1a009de?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(73, 'Máncora', 'Balneario norteño de renombre internacional caracterizado por sus playas de arena fina, sol radiante durante todo el año y olas perfectas para la práctica del surf y kitesurf. Destaca por su vida nocturna y gastronomía marina.', 'Piura, Talara', -4.106411, -81.048472, 'Playa', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(74, 'Playa El Ñuro', 'Caleta de pescadores famosa por haberse convertido en un refugio natural de tortugas marinas verdes. Los visitantes pueden nadar de forma regulada junto a estos dóciles animales desde el muelle artesanal.', 'Piura, Talara', -4.215541, -81.183424, 'Naturaleza', 'https://images.unsplash.com/photo-1559583985-c80d8ad9b29f?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(75, 'Playa Punta Sal', 'Una de las playas más hermosas, tranquilas y exclusivas del norte peruano. Sus aguas son cálidas debido a la corriente de El Niño, casi no tiene olas y es un lugar predilecto para el avistamiento de ballenas jorobadas.', 'Tumbes, Contralmirante Villar', -3.982247, -80.974412, 'Playa', 'https://images.unsplash.com/photo-1473442240418-452f03b7ae40?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(76, 'Santuario Nacional Manglares de Tumbes', 'Ecosistema boscoso de manglares donde el agua dulce del río se mezcla con el océano. Hogar de especies únicas como las conchas negras, los cangrejos del manglar, cocodrilos americanos y una gran variedad de aves.', 'Tumbes, Zarumilla', -3.483122, -80.293411, 'Naturaleza', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(77, 'Playa Cabo Blanco', 'Mítica playa pesquera cuyas olas de tubo perfecto la convirtieron en un templo del surf mundial. Es famosa históricamente porque el escritor Ernest Hemingway acudía aquí para la pesca del merlín negro gigante.', 'Piura, Talara', -4.251412, -81.232414, 'Playa', 'https://images.unsplash.com/photo-1502680390469-be75c86b636f?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(78, 'Catarata Velo de la Novia', 'Espectacular cascada ubicada en el Boquerón del Padre Abad. Su caída de agua de más de 60 metros sobre rocas cubiertas de musgo y helechos asemeja un gigantesco y fino velo blanco de novia, ideal para refrescarse.', 'Ucayali, Padre Abad', -9.032212, -75.721411, 'Naturaleza', 'https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(79, 'Laguna de Yarinacocha', 'Una de las lagunas más grandes de la Amazonía peruana, formada por un antiguo brazo del río Ucayali. En sus orillas se asientan comunidades de la etnia Shipibo-Conibo que ofrecen artesanía y medicina tradicional.', 'Ucayali, Coronel Portillo', -8.351412, -74.571412, 'Cultural', 'https://images.unsplash.com/photo-1500485035595-cbe6f645feb1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(80, 'Bosque de Protección Alto Mayo', 'Área protegida de selva alta con ecosistemas montañosos húmedos y nacientes de ríos. Destaca por su altísima diversidad de orquídeas salvajes, aves endémicas como el lechucito bigotón y producción de café sostenible.', 'San Martín, Rioja', -5.694122, -77.612411, 'Naturaleza', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(81, 'Laguna Azul (El Sauce)', 'Espléndido y pacífico cuerpo de agua de origen volcánico rodeado de verdes colinas en la selva alta de San Martín. Es un destino predilecto para deportes acuáticos, paseos en bote, pesca recreativa y relajo.', 'San Martín, Tarapoto', -6.618412, -76.221412, 'Naturaleza', 'https://images.unsplash.com/photo-1472214222541-d510753a4907?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(82, 'Santuario Histórico de la Pampa de Ayacucho', 'Extensa planicie donde se libró la Batalla de Ayacucho en 1824, consolidando la independencia de toda Sudamérica. Está coronada por un imponente obelisco de mármol blanco de 44 metros de altura.', 'Ayacucho, Huamanga', -13.041122, -74.123411, 'Histórico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(83, 'Catarata Ahuashiyacu', 'Impresionante caída de agua de 40 metros ubicada a pocos minutos de Tarapoto. Su nombre significa agua cantarina, y su piscina natural al fondo es perfecta para nadar rodeado de frondosos helechos y árboles.', 'San Martín, Tarapoto', -6.454311, -76.303412, 'Naturaleza', 'https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(84, 'Complejo Arqueológico de Ventanillas de Otuzco', 'Necrópolis preínca de la cultura Cajamarca tallada directamente sobre paredes verticales de roca volcánica. Consiste en cientos de nichos o criptas cuadradas que simulan ventanas donde se sepultaba a los nobles.', 'Cajamarca, Cajamarca', -7.123412, -78.473412, 'Arqueológico', 'https://images.unsplash.com/photo-1599925232924-406cb75267ea?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(85, 'Cuarto del Rescate de Atahualpa', 'El único vestigio arquitectónico inca que se conserva en la ciudad de Cajamarca. Es la histórica habitación donde el último emperador inca, Atahualpa, estuvo prisionero y prometió llenarlo una vez de oro y dos de plata.', 'Cajamarca, Cajamarca', -7.155412, -78.514311, 'Histórico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:37'),
(86, 'Santuario Histórico de Chacamarca', 'Extensa planicie altoandina a más de 4,000 metros de altitud donde se libró la Batalla de Junín en 1824. Alberga el imponente Monumento a los Vencedores de Junín y protege ecosistemas de bofedales y fauna andina.', 'Junín, Junín', -11.121412, -75.983412, 'Histórico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(87, 'Valle del Mantaro', 'Extenso y fértil valle andino rodeado de imponentes montañas, cuna de ricas tradiciones folclóricas, pueblos artesanales dedicados al mate burilado y textilería, y una gastronomía andina única basada en la papa.', 'Junín, Huancayo', -11.951412, -75.333412, 'Cultural', 'https://images.unsplash.com/photo-1472214222541-d510753a4907?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(88, 'Bosque de Piedras de Huayllay', 'Impresionante santuario nacional conformado por miles de formaciones rocosas de origen volcánico que asemejan perfiles humanos y animales gigantescos. Es considerado uno de los museos geológicos naturales más grandes del mundo.', 'Pasco, Pasco', -10.993412, -76.321411, 'Naturaleza', 'https://images.unsplash.com/photo-1518098268026-4e43a1a009de?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(89, 'Complejo Arqueológico de Tantarica', 'Antiguo centro administrativo y religioso preínca edificado en piedra sobre la cima de un cerro, con terrazas y murallas que controlaban el acceso al valle alto. Destaca por su planeamiento urbano defensivo.', 'Cajamarca, Contumazá', -7.371412, -78.813412, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(90, 'Nevado Huandoy', 'Imponente montaña de cuatro picos situada en la Cordillera Blanca dentro del Parque Nacional Huascarán. Sus imponentes paredes de hielo y roca son el escenario de desafiantes rutas de escalada de alta dificultad mundial.', 'Ancash, Yungay', -9.031412, -77.663412, 'Naturaleza', 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(91, 'Ciudad Sagrada de Caral', 'La civilización más antigua de América, contemporánea con las de Egipto y Mesopotamia. Complejo arqueológico monumental compuesto por pirámides de piedra truncas, plazas circulares hundidas y un avanzado diseño urbano.', 'Lima, Barranca', -10.892742, -77.518621, 'Arqueológico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(92, 'Reserva Paisajística Nor Yauyos-Cochas', 'Espectacular paraíso andino donde el río Cañete forma una sucesión de cascadas escalonadas de aguas turquesas cristalinas y lagunas rodeadas de bosques de queñuales y andenerías preíncas perfectamente conservadas.', 'Lima, Yauyos', -12.281412, -75.833412, 'Naturaleza', 'https://images.unsplash.com/photo-1433832597046-4f10e10ac764?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(93, 'Complejo Arqueológico de Rúpac', 'Conocido popularmente como el Machu Picchu limeño, es una imponente fortaleza de la cultura Atavillos situada sobre la cresta de una montaña alta. Sus edificaciones de piedra de tres pisos se mantienen intactas sobre las nubes.', 'Lima, Huaral', -11.321412, -76.813412, 'Aventura', 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(94, 'Santuario Arqueológico de Pachacámac', 'El centro ceremonial más importante de la costa central peruana durante más de mil años, dedicado al temido dios Pachacámac. Alberga templos piramidales de adobe, plazas, palacios y un moderno museo de sitio.', 'Lima, Lurín', -12.257342, -76.901234, 'Arqueológico', 'https://images.unsplash.com/photo-1619542402915-dcaf30e4e2a1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(95, 'Lunahuaná', 'Fértil valle costero con excelente clima templado y sol todo el año, famoso por la producción artesanal de piscos y vinos. Es el destino favorito en Lima para la práctica de deportes de aventura como canotaje y canopy.', 'Lima, Cañete', -12.961412, -76.133412, 'Aventura', 'https://images.unsplash.com/photo-1534447677768-be436bb09401?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(96, 'Lomas de Lachay', 'Reserva nacional costera que constituye un ecosistema único de oasis de neblina. Durante el invierno, la intensa humedad desértica transforma los áridos cerros de piedra en verdes y densos pastizales llenos de fauna silvestre.', 'Lima, Huaura', -11.361412, -77.373412, 'Naturaleza', 'https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(97, 'Líneas de Palpa', 'Geoglifos prehispánicos tallados en las laderas de los cerros de Palpa, atribuidos a la cultura Paracas. A diferencia de las de Nazca, muchas de estas figuras representan grupos humanos de perfil y son visibles desde tierra.', 'Ica, Palpa', -14.521412, -75.183412, 'Arqueológico', 'https://images.unsplash.com/photo-1622325492193-273a5a76c024?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(98, 'Playa Tuquillo', 'Hermosa ensenada costera conocida como la piscina del Pacífico debido a sus mansas y cristalinas aguas color turquesa, protegida por una barrera natural de rocas marinas. Ideal para el veraneo familiar y campamentos.', 'Ancash, Huarmey', -10.013412, -78.183412, 'Playa', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(99, 'Laguna de Paca', 'Espejo de agua rodeado de extensos totorales en el Valle del Mantaro. Envuelto en leyendas locales sobre tesoros incas sumergidos, ofrece paseos turísticos en bote y restaurantes tradicionales a sus orillas.', 'Junín, Jauja', -11.721412, -75.503412, 'Naturaleza', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(100, 'Baños del Inca', 'Complejo termomedicinal famoso por sus pozas naturales de aguas volcánicas calientes con propiedades curativas. Históricamente fue el lugar de descanso y relajación predilecto del soberano inca Atahualpa.', 'Cajamarca, Cajamarca', -7.161412, -78.463412, 'Naturaleza', 'https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(101, 'Barrio de Santa Ana en Ayacucho', 'Barrio tradicional artesanal famoso por concentrar los talleres de los maestros talladores de piedra de Huamanga y tejedores de tapices de lana policroma. Corazón cultural del arte popular andino del Perú.', 'Ayacucho, Huamanga', -13.161412, -74.223412, 'Cultural', 'https://images.unsplash.com/photo-1568231266584-8b54906cd523?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(102, 'Complejo Arqueológico de Wari', 'La gigantesca urbe prehispánica que fue capital del Imperio Wari. El sitio arqueológico comprende sectores amurallados de piedra rústica, plazas, cámaras funerarias subterráneas y un museo de sitio expositivo.', 'Ayacucho, Huamanga', -13.061412, -74.193412, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(103, 'Bosque de Piedras de Ccochaccahuana', 'Enigmática formación geológica de torres y agujas de piedra esculpidas por el viento y la lluvia a lo largo de los siglos. Paisaje místico andino ideal para el turismo místico y la fotografía de naturaleza de montaña.', 'Apurímac, Andahuaylas', -13.651412, -73.383412, 'Naturaleza', 'https://images.unsplash.com/photo-1483728642387-6c3bdd6c93e5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(104, 'Laguna de Pacucha', 'Una de las lagunas más grandes y bellas de Apurímac, de aguas templadas y azules rodeadas de pastizales. Cerca se encuentra el complejo Sóndor, centro ceremonial de la guerrera cultura Chanka.', 'Apurímac, Andahuaylas', -13.603412, -73.301412, 'Naturaleza', 'https://images.unsplash.com/photo-1500485035595-cbe6f645feb1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(105, 'Complejo Arqueológico de Sóndor', 'Santuario piramidal de la cultura Chanka, posteriormente ocupado por los incas. Situado estratégicamente en una colina con vistas a la laguna de Pacucha, fue escenario de cruentos enfrentamientos históricos.', 'Apurímac, Andahuaylas', -13.611412, -73.313412, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(106, 'Playa Zorritos', 'Balneario norteño de aguas cálidas tropicales y arena fina, con sol garantizado durante todas las estaciones. Es perfecto para el descanso, la pesca deportiva y caminatas tranquilas frente al mar.', 'Tumbes, Contralmirante Villar', -3.673412, -80.673412, 'Playa', 'https://images.unsplash.com/photo-1473442240418-452f03b7ae40?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(107, 'Santuario Nacional de Calipuy', 'Área protegida andina destinada a la conservación de la población más grande de Puya Raimondi, una planta colosal que florece una sola vez cada 100 años con miles de flores. Hábitat del oso de anteojos.', 'La Libertad, Santiago de Chuco', -8.411412, -78.303412, 'Naturaleza', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(108, 'Pozuzo', 'Única colonia austro-alemana en el mundo establecida en plena selva alta central del Perú. Destaca por su arquitectura europea de madera, sus tradiciones de bailes tiroleses y gastronomía fusionada.', 'Pasco, Oxapampa', -10.071412, -75.553412, 'Cultural', 'https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(109, 'Oxapampa', 'Ciudad rodeada de bosques de neblina en la selva central, reconocida por la UNESCO como Reserva de Biosfera. Famosa por sus casonas de madera de estilo europeo, ganadería y producción de café orgánico.', 'Pasco, Oxapampa', -10.573412, -75.401412, 'Cultural', 'https://images.unsplash.com/photo-1516026672322-bc52d61a55d5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(110, 'Catarata Las Tres Reinas', 'Escondida caída de agua triple en la selva central, accesible mediante una emocionante caminata de aventura por el cañón de un río. Ideal para el trekking de selva y observación de naturaleza exótica.', 'Pasco, Oxapampa', -10.591412, -75.381412, 'Aventura', 'https://images.unsplash.com/photo-1547036967-23d11aacaee0?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:26:48'),
(111, 'Valle de Géiseres de Candarave', 'Impresionante campo geotérmico ubicado a más de 4,300 metros de altitud en el sur peruano. Cuenta con más de 85 fuentes termales y fumarolas activas que expulsan aguas sulfurosas calientes sobre los 80°C.', 'Tacna, Candarave', -17.183412, -70.151412, 'Naturaleza', 'https://images.unsplash.com/photo-1518098268026-4e43a1a009de?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(112, 'Petroglifos de Miculla', 'Uno de los complejos de arte rupestre más extensos de Sudamérica, con miles de rocas talladas que datan de la cultura Tiahuanaco y Estuquiña. Muestra escenas de caza, constelaciones, fauna andina y rituales.', 'Tacna, Tacna', -17.913412, -70.121412, 'Arqueológico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(113, 'Ruta del Pisco de Moquegua', 'Recorrido enológico a través de bodegas coloniales situadas en el fértil valle de Moquegua. Destaca por la producción tradicional de piscos premium, licores de damasco y vinos con técnicas de herencia española.', 'Moquegua, Mariscal Nieto', -17.193412, -70.931412, 'Cultural', 'https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(114, 'Parque Nacional Bahuaja Sonene', 'Santuario ecológico intangible que protege la única sabana húmeda tropical de Sudamérica (las Pampas del Heath). Hábitat del rarísimo lobo de crin, ciervo de los pantanos, nutrias gigantes y felinos amazónicos.', 'Madre de Dios, Tambopata', -13.251412, -68.853412, 'Naturaleza', 'https://images.unsplash.com/photo-1516026672322-bc52d61a55d5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(115, 'Complejo Arqueológico de Sillustani', 'Célebre cementerio preínca e inca a orillas de la laguna Umayo. Destaca por sus monumentales chullpas, imponentes torres de piedra tallada de forma cilíndrica construidas para albergar los restos de la nobleza Qulla.', 'Puno, Puno', -15.719612, -70.158412, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(116, 'Cañón de Tinajani', 'Espectacular desfiladero de formaciones geológicas de roca arenisca de tonalidades rojizas que superan los 50 metros de altura. Un paisaje imponente envuelto en un silencio místico y leyendas altoandinas.', 'Puno, Melgar', -14.931412, -70.583412, 'Naturaleza', 'https://images.unsplash.com/photo-1483728642387-6c3bdd6c93e5?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(117, 'Valle de los Volcanes de Andagua', 'Extraordinario paisaje geológico surrealista compuesto por más de 80 pequeños conos volcánicos extintos que emergen del suelo del valle. Un escenario único que simula de forma impactante la superficie de la luna.', 'Arequipa, Castilla', -15.411412, -72.353412, 'Naturaleza', 'https://images.unsplash.com/photo-1518098268026-4e43a1a009de?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(118, 'Laguna de Salinas', 'Espejo de agua salobre de alta montaña ubicado dentro de la Reserva Nacional de Salinas y Aguada Blanca. Cambia dramáticamente según las estaciones y es el santuario de nidificación de miles de flamencos andinos.', 'Arequipa, Arequipa', -16.361412, -71.133412, 'Naturaleza', 'https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(119, 'Tren Macho (Ruta Huancayo - Huancavelica)', 'Histórica línea ferroviaria andina que cruza impresionantes abismos, túneles picados a mano en la roca y puentes sobre ríos torrentosos, conectando las regiones andinas del centro con espectaculares paisajes.', 'Huancavelica, Huancavelica', -12.451412, -75.123412, 'Aventura', 'https://images.unsplash.com/photo-1544816155-12df9643f363?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(120, 'Complejo Arqueológico de Inka Wasi', 'Centro militar y administrativo inca edificado fielmente a semejanza del Cusco en el valle de Cañete. Conserva calles, plazas, aposentos reales y bodegas de almacenamiento de suministros perfectamente distribuidos.', 'Lima, Cañete', -12.983412, -76.151412, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(121, 'Playa La Mina', 'Hermosa caleta oculta dentro de la Reserva Nacional de Paracas. Es famosa por la tonalidad esmeralda de sus aguas extremadamente calmas y la fina arena blanca que la rodea, un paraíso natural costero.', 'Ica, Pisco', -13.881412, -76.313412, 'Playa', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(122, 'Písaq (Sitio Arqueológico)', 'Complejo arqueológico incaico situado sobre una montaña que vigila el Valle Sagrado. Famoso por su colosal sistema de andenerías agrícolas, torreones militares, baños rituales y su cementerio prehispánico.', 'Cusco, Calca', -13.413412, -71.843412, 'Arqueológico', 'https://images.unsplash.com/photo-1569336415962-a4bd9f69cd83?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(123, 'Tipón', 'Maravilla de la ingeniería hidráulica incaica. Consiste en un complejo ceremonial de terrazas donde el agua brota de manantiales subterráneos y fluye con precisión milimétrica a través de canales tallados en piedra.', 'Cusco, Quispicanchi', -13.568412, -71.783412, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(124, 'Raqch\'i (Templo de Wiracocha)', 'Santuario inca de dimensiones colosales dedicado al dios creador Wiracocha. Destaca por sus monumentales muros de barro y piedra de 14 metros de altura, además de sus decenas de qollcas o almacenes circulares.', 'Cusco, Canchis', -14.193412, -71.363412, 'Arqueológico', 'https://images.unsplash.com/photo-1605538032432-a9f0c8d9baac?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(125, 'Puka Pukara', 'Fortaleza militar incaica compuesta por terrazas superpuestas, acueductos y cámaras interiores. Funcionaba como un puesto de control defensivo y cuartel de abastecimiento para las tropas del inca.', 'Cusco, Cusco', -13.483412, -71.961412, 'Arqueológico', 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(126, 'Tambomachay', 'Sitio arqueológico dedicado al culto del agua y balneario de descanso de la élite incaica. Cuenta con una serie de canales, acueductos y cascadas de agua limpia que fluyen sobre muros de sillería fina.', 'Cusco, Cusco', -13.471412, -71.963412, 'Arqueológico', 'https://images.unsplash.com/photo-1590050752117-238cb0fb12b1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(127, 'Quistococha (Complejo Turístico)', 'Parque y reserva natural a pocos minutos de Iquitos que rodea la laguna del mismo nombre. Cuenta con una playa de arena blanca artificial, un zoológico de rescate de fauna amazónica y densos bosques tropicales.', 'Loreto, Maynas', -3.823412, -73.321412, 'Naturaleza', 'https://images.unsplash.com/photo-1547036967-23d11aacaee0?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(128, 'Chazuta', 'Pueblo tradicional amazónico a orillas del río Huallaga, famoso por su herencia cultural de cerámica ancestral declarada Patrimonio de la Nación. Es un centro activo de turismo comunitario y cacao artesanal.', 'San Martín, San Martín', -6.571412, -76.133412, 'Cultural', 'https://images.unsplash.com/photo-1500485035595-cbe6f645feb1?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(129, 'Moyobamba (Ciudad de las Orquídeas)', 'Capital de la región San Martín, ubicada en el valle del Alto Mayo. Es reconocida por su clima templado, sus abundantes baños termales de San Mateo y sus viveros que albergan miles de especies de orquídeas.', 'San Martín, Moyobamba', -6.031412, -76.963412, 'Naturaleza', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(130, 'Complejo Arqueológico de Túcume', 'Impresionante valle que concentra 26 pirámides colosales de adobe construidas por la cultura Lambayeque. Destaca Huaca Larga, la estructura de barro más grande de América del Sur, y un museo interactivo.', 'Lambayeque, Lambayeque', -6.513412, -79.843412, 'Arqueológico', 'https://images.unsplash.com/photo-1599940824399-b87987ceb72a?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(131, 'Bosque de Pómac', 'Santuario histórico nacional que protege la densidad más grande de algarrobos del planeta sobre una pampa desértica. Custodia además las pirámides de barro de la cultura Sicán, donde se halló el famoso Tumi de oro.', 'Lambayeque, Ferreñafe', -6.483412, -79.783412, 'Naturaleza', 'https://images.unsplash.com/photo-1511497584788-876760111969?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(132, 'Playa Tortugas', 'Tranquilo y hermoso balneario costero encerrado en una bahía de aguas mansas y transparentes. Es un destino predilecto en el norte medio para paseos en yate, pesca, buceo deportivo y degustación de cebiches tradicionales.', 'Ancash, Casma', -9.361412, -78.413412, 'Playa', 'https://images.unsplash.com/photo-1473442240418-452f03b7ae40?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(133, 'Complejo Arqueológico Sechín', 'Templo sagrado de la cultura Sechín construido enteramente de piedra. Destaca por sus impresionantes monolitos grabados en la fachada que representan a guerreros armados y feroces escenas rituales de sacrificios humanos.', 'Ancash, Casma', -9.471412, -78.293412, 'Arqueológico', 'https://images.unsplash.com/photo-1599925232924-406cb75267ea?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(134, 'Las Huaringas', 'Conjunto de 14 lagunas sagradas ubicadas en la alta cordillera andina de Piura a más de 3,500 metros. Centro por excelencia del curanderismo y chamanismo andino ancestral, donde acuden visitantes por baños rituales florecientes.', 'Piura, Huancabamba', -5.031412, -79.453412, 'Cultural', 'https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01'),
(135, 'Pueblo Tradicional de Catacaos', 'Villa costera piurana reconocida como la capital artesanal de la región. Famosa a nivel nacional por sus extraordinarios trabajos de filigrana en plata y oro, tejidos de sombreros de paja toquilla y picanterías tradicionales.', 'Piura, Piura', -5.263412, -80.673412, 'Cultural', 'https://images.unsplash.com/photo-1568231266584-8b54906cd523?auto=format&fit=crop&w=600&h=600', '2026-07-04 01:27:01');